sql:
SELECT COUNT(assay_id) AS assay_count
FROM assays
WHERE sample_id = 1;

SELECT run_name
FROM assays
WHERE assay_method = 'DDA' AND assay_duration > 30;

external_knowledge:
- 'DDA' stands for Data-Dependent Acquisition, a mass spectrometry acquisition method; 
- 'MaxQuant' is a software package for mass spectrometry-based quantitative proteomics; 
- Access duration is in seconds, and 300 seconds is equivalent to 5 minutes.

sql:
SELECT assay_id
FROM assays
ORDER BY assay_id;

SELECT COUNT(assay_id) AS assay_count
FROM assays
WHERE assay_date = '2023-01-01';
